use data::*;

macro_rules! implies {
  ($lhs: expr, $rhs: expr) => {
    !$lhs || $rhs
  };
}

macro_rules! impliesL {
  ($lhs: expr, $rhs: expr) => {
    !$lhs | $rhs
  };
}

/** Compute Entrypoint Contract
  *
  * guarantee g1
  * @param api_write_port outgoing event port
  */
pub fn compute_spec_g1_guarantee(api_write_port: Option<u8>) -> bool
{
  implies!(
    true,
    api_write_port.is_some())
}

/** CEP-T-Guar: Top-level guarantee contracts for producer's compute entrypoint
  *
  * @param api_write_port outgoing event port
  */
pub fn compute_CEP_T_Guar(api_write_port: Option<u8>) -> bool
{
  let r0: bool = compute_spec_g1_guarantee(api_write_port);

  return r0;
}

/** CEP-Post: Compute Entrypoint Post-Condition for producer
  *
  * @param api_write_port outgoing event port
  */
pub fn compute_CEP_Post(api_write_port: Option<u8>) -> bool
{
  // CEP-Guar: guarantee clauses of producer's compute entrypoint
  let r0: bool = compute_CEP_T_Guar(api_write_port);

  return r0;
}
